  const insertClient = "INSERT INTO cfdi_clients (client_id, display_name, razon_social, rfc, tipo_persona, regimen_fiscal, codigo_postal_fiscal, uso_cfdi_default, tax_profile, validated_by_human, enabled, notes, created_at, updated_at) VALUES (" + sqlQuote(clientId) + ", " + sqlQuote(name) + ", " + sqlQuote(fields.razon_social || null) + ", " + sqlQuote(fields.rfc || null) + ", " + sqlQuote(tipo) + ", " + sqlQuote(fields.regimen_fiscal || null) + ", " + sqlQuote(fields.cp_fiscal || fields.codigo_postal_fiscal || null) + ", " + sqlQuote(fields.uso_cfdi || fields.uso_cfdi_default || null) + ", " + sqlQuote(profile) + ", false, true, " + sqlQuote("Alta manual desde Telegram. Revisar antes de confiar en retenciones.") + ", now(), now()) ON CONFLICT (client_id) DO UPDATE SET display_name = EXCLUDED.display_name, razon_social = EXCLUDED.razon_social, rfc = EXCLUDED.rfc, tipo_persona = EXCLUDED.tipo_persona, regimen_fiscal = EXCLUDED.regimen_fiscal, codigo_postal_fiscal = EXCLUDED.codigo_postal_fiscal, uso_cfdi_default = EXCLUDED.uso_cfdi_default, tax_profile = EXCLUDED.tax_profile, validated_by_human = false, updated_at = now();";
