function editClientStatement(clientId, field, value) {
  const allowed = { display_name: "display_name", razon_social: "razon_social", rfc: "rfc", regimen_fiscal: "regimen_fiscal", regimen_fiscal_label: "regimen_fiscal_label", codigo_postal_fiscal: "codigo_postal_fiscal", uso_cfdi_default: "uso_cfdi_default", tipo_persona: "tipo_persona", tax_profile: "tax_profile", enabled: "enabled" };
  const column = allowed[String(field || "").toLowerCase()];
  if (!column) return null;
  const valueSql = column === "enabled" ? sqlBool(["true", "si", "1", "activo", "enabled"].includes(normalizedKey(value))) : sqlQuote(value);
  const critical = ["razon_social", "rfc", "regimen_fiscal", "regimen_fiscal_label", "codigo_postal_fiscal", "uso_cfdi_default", "tipo_persona", "tax_profile"].includes(column);
  return "UPDATE cfdi_clients SET " + column + " = " + valueSql + (critical ? ", validated_by_human = false" : "") + ", updated_at = now() WHERE client_id = " + sqlQuote(clientId) + ";";
}

