  const eventId = idFromTimestamp('CLV', timestamp, updateId);
  const conditions = 'client_id = ' + sqlQuote(clientId) + " AND COALESCE(NULLIF(rfc, ''), '') <> '' AND COALESCE(NULLIF(regimen_fiscal, ''), '') <> '' AND COALESCE(NULLIF(codigo_postal_fiscal, ''), '') <> ''";
