}

function selectTaxRule(client, operationType, taxRules) {
  if (!client) return { rule: null, reason: "sin_cliente", canCalculateRetentions: false };
  if (client.validated_by_human !== true) return { rule: null, reason: "cliente_no_validado", canCalculateRetentions: false };
  if (!hasMinimumTaxIdentity(client)) return { rule: null, reason: "cliente_incompleto", canCalculateRetentions: false };
  const tipo = String(client.tipo_persona || "DESCONOCIDO").toUpperCase();
  const profile = String(client.tax_profile || (tipo === "FISICA" ? "PF_GENERAL" : tipo === "MORAL_SIN_FINES_LUCRO" ? "PM_NO_LUCRATIVA" : tipo === "MORAL" ? "PM_GENERAL" : "DESCONOCIDO")).toUpperCase();
  const op = String(operationType || "SERVICIO").toUpperCase();
  const candidates = (taxRules || []).filter((rule) => {
    const rt = String(rule.receiver_tipo_persona || "").toUpperCase();
    const rp = String(rule.receiver_tax_profile || "").toUpperCase();
    const ro = String(rule.operation_type || "").toUpperCase();
    return (!rt || rt === tipo) && (!rp || rp === profile) && (!ro || ro === op || (op === "SERVICIO_INSTALACION" && ro === "SERVICIO"));
  }).sort((a, b) => {
    const leftExact = String(a.operation_type || "").toUpperCase() === op ? 1 : 0;
    const rightExact = String(b.operation_type || "").toUpperCase() === op ? 1 : 0;
    return rightExact - leftExact;
  });
  return { rule: candidates[0] || null, reason: candidates[0] ? "rule:" + candidates[0].rule_id : "sin_regla", canCalculateRetentions: Boolean(candidates[0]) };
}

