function isHelpIntent(text) {
  const raw = String(text || "").trim();
  const normalized = normalizedKey(raw);
  if (!normalized && raw !== "?") return false;
  if (raw === "?") return true;
  const hints = ["que necesitas", "que necesito", "que hago", "que debo hacer", "trabajo", "ayuda", "no entiendo"];
  return hints.some((hint) => {
    const key = normalizedKey(hint);
    return normalized === key || (normalized.length <= 24 && normalized.includes(key));
  });
}

function normalizeBlocker(blocker) {
  if (!blocker) return null;
  if (typeof blocker === "string") return { type: blocker };
  return blocker;
}

function formatBlocker(blocker) {
  const item = normalizeBlocker(blocker);
  if (!item) return "- pendiente sin detalle";
  if (item.type === "linea_ambigua") return "* linea " + (item.line_number || "?") + ": " + (item.missing_reason || "falta sistema/equipo");
  if (item.type === "monto_faltante") return "* monto: falta monto";
  if (item.type === "iva_faltante") return "* IVA: falta indicar +IVA o IVA incluido";
  if (item.type === "cliente_ambiguo") return "* cliente: falta confirmar si es " + (item.suggested_name || "el cliente sugerido");
  if (item.type === "cliente_no_confirmado") return "* cliente: no confirmado";
  if (item.type === "concepto_bloqueado") return "* concepto: bloqueado o fuera de actividad";
  return "* " + (item.type || "pendiente");
}

function blockersMessage(blockers) {
