function explainLineClarification(stateContext) {
  const lineNumber = stateContext.line_number || stateContext.pending_invoice_context?.blockers?.[0]?.line_number || "?";
  const lineText = stateContext.line_text || stateContext.pending_invoice_context?.blockers?.[0]?.line_text || "";
