  return appendWorkflowVersion(commandResult("LINE_NEEDS_CLARIFICATION", lineClarificationMessage(lineNumber, lineText, missingReason), { state: "LINE_NEEDS_CLARIFICATION", line_number: lineNumber, missing_reason: missingReason }));
}

function familyClarificationSuffix(text) {
  const normalized = normalizedKey(text);
  if (!normalized) return "";
  if (/^(?:\d+\s+)?(?:linea\s+\d+\s+|linea\s*)?cctv$/.test(normalized) || normalized.includes(" cctv")) return "CCTV";
  if (/^(?:\d+\s+)?(?:linea\s+\d+\s+|linea\s*)?red$/.test(normalized) || normalized.includes(" red")) return "red";
  if (/^(?:\d+\s+)?(?:linea\s+\d+\s+|linea\s*)?computo$/.test(normalized) || normalized.includes(" computo")) return "computo";
  if (normalized.includes("control de acceso")) return "control de acceso";
  if (/^(?:\d+\s+)?(?:linea\s+\d+\s+|linea\s*)?barrera$/.test(normalized) || normalized.includes(" barrera")) return "barrera";
  return "";
}

function parseLineClarificationText(text, fallbackLineNumber) {
  const raw = String(text || "").trim();
  const normalized = normalizedKey(raw);
  const editMatch = raw.match(/^\/?editlinea\s+(\d+)\s+([\s\S]+)$/i);
  if (editMatch) return { mode: "EDIT", lineNumber: Number(editMatch[1]), text: editMatch[2].trim() };
  const numberedFamily = normalized.match(/^(?:linea\s+)?(\d+)\s+(cctv|red|computo|control de acceso|barrera)$/);
  if (numberedFamily) return { mode: "FAMILY", lineNumber: Number(numberedFamily[1]), family: numberedFamily[2] };
  const family = familyClarificationSuffix(raw);
  if (family) return { mode: "FAMILY", lineNumber: Number(fallbackLineNumber || 1), family };
  return { mode: "UNKNOWN", lineNumber: Number(fallbackLineNumber || 1), text: raw };
}

function applyFamilyToRawLine(raw, family) {
  const cleanRaw = String(raw || "").trim();
  const cleanFamily = String(family || "").trim();
  if (!cleanFamily) return cleanRaw;
  const withoutGeneric = cleanRaw.replace(/\b(servicio\s+tecnico\s+general|servicio\s+general|revision\s+general|mantenimiento\s+general)\b/ig, "servicio tecnico").replace(/\s+/g, " ").trim();
  const normalized = normalizedKey(withoutGeneric);
  if (normalized.includes(normalizedKey(cleanFamily))) return withoutGeneric;
  return (withoutGeneric + " " + cleanFamily).replace(/\s+/g, " ").trim();
}

function mergeLineClarification(stateContext, clarificationText) {
  const pending = { ...(stateContext.pending_invoice_context || stateContext.invoice_context || {}) };
  const fallbackLineNumber = Number(stateContext.line_number || pending.blockers?.[0]?.line_number || 1);
  const parsed = parseLineClarificationText(clarificationText, fallbackLineNumber);
  if (parsed.mode === "EDIT") return applyEditLine(pending, parsed.lineNumber, parsed.text);
  if (parsed.mode !== "FAMILY") return explainLineClarification(stateContext);
  const pendingLines = stateContext.pending_lines || pending.line_items || [];
  const updatedLines = pendingLines.map((item) => {
    if (Number(item.line_number) !== Number(parsed.lineNumber)) return item;
    const sourceRaw = String(item.raw || item.work_text || stateContext.line_text || "").trim();
    return buildRawLineItem(parsed.lineNumber, applyFamilyToRawLine(sourceRaw, parsed.family));
  });
  pending.line_items = updatedLines.length ? updatedLines : [buildRawLineItem(parsed.lineNumber, applyFamilyToRawLine(stateContext.line_text || pending.work_text || "", parsed.family))];
  pending.blockers = [];
  return processMultilineInvoiceContext(pending);
